import React from "react";
import Menu from "./Menu";

function App() {
  const menuItems = [
    {
      id: 1,
      name: "Garlic Bread",
      description: "Classic garlic bread, with a hint of herbs.",
      price: 5,
    },
    {
      id: 2,
      name: "Soup of the Day",
      description: "A delicious way to start your meal.",
      price: 7,
    },
    {
      id: 3,
      name: "Grilled Salmon",
      description: "Fresh salmon that's grilled to perfection.",
      price: 15,
    },
    {
      id: 4,
      name: "Steak",
      description: "High-quality beef with our special sauce.",
      price: 18,
    },
    {
      id: 5,
      name: "Cheesecake",
      description: "Creamy cheesecake with a crispy base.",
      price: 6,
    },
    {
      id: 6,
      name: "Ice Cream",
      description: "Choose from our variety of flavors.",
      price: 4,
    },
    {
      id: 7,
      name: "Caesar Salad",
      description: "Crisp romaine with Caesar dressing and parmesan.",
      price: 8,
    },
    {
      id: 8,
      name: "Chicken Wings",
      description: "Spicy wings with a side of ranch dressing.",
      price: 10,
    },
    {
      id: 9,
      name: "Pasta Carbonara",
      description: "Creamy pasta with pancetta and parmesan.",
      price: 12,
    },
    {
      id: 10,
      name: "Margherita Pizza",
      description: "Classic pizza with tomato, mozzarella, and basil.",
      price: 11,
    },
    {
      id: 11,
      name: "Tacos",
      description:
        "Soft tortillas filled with seasoned beef, lettuce, and cheese.",
      price: 9,
    },
    {
      id: 12,
      name: "BBQ Ribs",
      description: "Tender ribs slathered in barbecue sauce.",
      price: 17,
    },
    {
      id: 13,
      name: "Vegetarian Chili",
      description: "A hearty and spicy vegetarian chili.",
      price: 10,
    },
    {
      id: 14,
      name: "Beef Stroganoff",
      description: "Tender beef in a creamy mushroom sauce.",
      price: 14,
    },
    {
      id: 15,
      name: "Shrimp Scampi",
      description: "Shrimp sautéed in garlic butter and white wine.",
      price: 16,
    },
    {
      id: 16,
      name: "Lamb Chops",
      description: "Grilled lamb chops with a rosemary mint glaze.",
      price: 20,
    },
    {
      id: 17,
      name: "Fettuccine Alfredo",
      description: "Rich and creamy fettuccine pasta.",
      price: 13,
    },
    {
      id: 18,
      name: "Spring Rolls",
      description: "Crispy rolls filled with fresh vegetables.",
      price: 7,
    },
    {
      id: 19,
      name: "Pancakes",
      description: "Fluffy pancakes served with maple syrup and butter.",
      price: 8,
    },
    {
      id: 20,
      name: "Lemon Tart",
      description: "Tart and sweet lemon filling with a buttery crust.",
      price: 6,
    },
  ];

  return (
    <div className="App">
      <Menu menuItemsData={menuItems} />
    </div>
  );
}

export default App;
